     7→#ifndef _SOFA_PBRPC_RPC_MESSAGE_STREAM_H_
     8→#define _SOFA_PBRPC_RPC_MESSAGE_STREAM_H_
     9→
    10→#include <deque>
    11→
    12→#include <sofa/pbrpc/rpc_byte_stream.h>
    13→#include <sofa/pbrpc/buffer.h>
    14→#include <sofa/pbrpc/rpc_error_code.h>
    15→#include <sofa/pbrpc/rpc_message_header.h>
    16→#include <sofa/pbrpc/tran_buf_pool.h>
    17→#include <sofa/pbrpc/flow_controller.h>
    18→
    19→namespace sofa {
    20→namespace pbrpc {
    21→
    22→// The "SendCookie" type should has default constructor, and
    23→// should be copyable. 
    24→template <typename SendCookie>
    25→class RpcMessageStream : public RpcByteStream
    26→{
    27→public:
    28→    enum RoleType {
    29→        ROLE_TYPE_SERVER = 0,
    30→        ROLE_TYPE_CLIENT = 1,
    31→    };
    32→
    33→public:
    34→    RpcMessageStream(RoleType role_type, IOService& io_service, const RpcEndpoint& endpoint)
    35→        : RpcByteStream(io_service, endpoint)
    36→        , _role_type(role_type)
    37→        , _pending_message_count(0)
    38→        , _pending_data_size(0)
    39→        , _pending_buffer_size(0)
    40→        , _swapped_message_count(0)
    41→        , _swapped_data_size(0)
    42→        , _swapped_buffer_size(0)
    43→        , _max_pending_buffer_size(0)
    44→        , _read_quota_token(1)
    45→        , _write_quota_token(1)
    46→        , _total_sent_count(0)
    47→        , _total_sent_size(0)
    48→        , _total_received_count(0)
    49→        , _total_received_size(0)
    50→        , _sent_size(0)
    51→        , _sending_data(NULL)
    52→        , _sending_size(0)
    53→        , _received_message_size(0)
    54→        , _received_header_size(0)
    55→        , _receiving_header_identified(false)
    56→        , _tran_buf(NULL)
    57→        , _receiving_data(NULL)
    58→        , _receiving_size(0)
    59→        , _send_token(TOKEN_FREE)
    60→        , _receive_token(TOKEN_FREE)
    61→    {}
    62→
    63→    virtual ~RpcMessageStream()
    64→    {
    65→        if (_tran_buf != NULL)
    66→        {
    67→            TranBufPool::free(_tran_buf);
    68→            _tran_buf = NULL;
    69→        }
    70→    }
    71→
    72→    // Async send message to the remote endpoint. The message may be first
    73→    // put into a pending queue if the channel is busy at that time.
    74→    //
    75→    // Before starting sending data, the hook function "on_sending" will
    76→    // be called to check if the message still need to be sent.
    77→    //
    78→    // If send succeed, callback "on_sent" will be called;
    79→    // else, callback "on_send_failed" will be called. 
    80→    //
    81→    // @param message  the message to send, including header, meta and data.
    82→    // @param cookie  a cookie affiliated to the message, which can carry some
    83→    //                user's customized info. It will not be sent, but would
    84→    //                be passed to the callback function.
    85→    void async_send_message(
    86→            const ReadBufferPtr& message,
    87→            const SendCookie& cookie)
    88→    {
    89→        SOFA_PBRPC_FUNCTION_TRACE;
    90→
    91→        if (is_closed())
    92→        {
    93→            on_send_failed(RPC_ERROR_CONNECTION_CLOSED, message, cookie);
    94→            return;
    95→        }
    96→
    97→        put_into_pending_queue(message, cookie);
    98→
    99→        try_start_send();
   100→    }
   101→
   102→    // Set the flow controller.
   103→    void set_flow_controller(const FlowControllerPtr& flow_controller)
   104→    {
   105→        _flow_controller = flow_controller;
   106→    }
   107→
   108→    // Set the max size of pending buffer for send.
   109→    void set_max_pending_buffer_size(int64 max_pending_buffer_size)
   110→    {
   111→        _max_pending_buffer_size = max_pending_buffer_size;
   112→    }
   113→
   114→    // Get the max size of pending buffer for send.
   115→    int64 max_pending_buffer_size() const
   116→    {
   117→        return _max_pending_buffer_size;
   118→    }
   119→
   120→    // Get the current count of messages in the pending queue.
   121→    int pending_message_count() const
   122→    {
   123→        return _pending_message_count + _swapped_message_count;
   124→    }
   125→
   126→    // Get the current data size of messages in the pending queue.
   127→    int64 pending_data_size() const
   128→    {
   129→        return _pending_data_size + _swapped_data_size;
   130→    }
   131→
   132→    // Get the current buffer size occupied by the pending queue.
   133→    // This size may be larger than "pending_data_size".
   134→    int64 pending_buffer_size() const
   135→    {
   136→        return _pending_buffer_size + _swapped_buffer_size;
   137→    }
   138→
   139→    // Trigger receiving operator.
   140→    // @return true if suceessfully triggered
   141→    virtual bool trigger_receive()
   142→    {
   143→        _read_quota_token = 1;
   144→        return try_start_receive();
   145→    }
   146→
   147→    // Trigger sending operator.
   148→    // @return true if suceessfully triggered
   149→    virtual bool trigger_send()
   150→    {
   151→        _write_quota_token = 1;
   152→        return try_start_send();
   153→    }
   154→
   155→    // Get read quota token used for sorting the trigger order.
   156→    // Always no more than 0.
   157→    int read_quota_token() const
   158→    {
   159→        return _read_quota_token;
   160→    }
   161→
   162→    // Get write quota token used for sorting the trigger order.
   163→    // Always no more than 0.
   164→    int write_quota_token() const
   165→    {
   166→        return _write_quota_token;
   167→    }
   168→
   169→protected:
   170→    // Hook function on the point of starting the sending.
   171→    //
   172→    // If return true, go ahead with the sending;
   173→    // else, cancel the sending.
   174→    //
   175→    // This hook may be useful when the message stayed in a sending waiting
   176→    // queue for some time, but when dequed, it is already timeout.
   177→    virtual bool on_sending(
   178→            const ReadBufferPtr& message,
   179→            const SendCookie& cookie) = 0;
   180→
   181→    // Callback function when send message succeed.
   182→    virtual void on_sent(
   183→            const ReadBufferPtr& message,
   184→            const SendCookie& cookie) = 0;
   185→
   186→    // Callback function when send message failed.
   187→    virtual void on_send_failed(
   188→            RpcErrorCode error_code,
   189→            const ReadBufferPtr& message,
   190→            const SendCookie& cookie) = 0;
   191→
   192→    // Hook function when received message.
   193→    // @param message  the rough received message, including meta and data.
   194→    // @param meta_size  the size of meta.
   195→    // @param data_size  the size of data.
   196→    virtual void on_received(
   197→            const ReadBufferPtr& message,
   198→            int meta_size,
   199→            int64 data_size) = 0;
   200→
   201→private:
   202→    virtual bool on_connected()
   203→    {
   204→        SOFA_PBRPC_FUNCTION_TRACE;
   205→
   206→        // prepare receiving
   207→        reset_receiving_env();
   208→        if (!reset_tran_buf())
   209→        {
   210→            close("out of memory");
   211→            return false;
   212→        }
   213→        return true;
   214→    }
   215→
   216→    // Callback of "async_read_some()".
   217→    virtual void on_read_some(
   218→            const boost::system::error_code& error,
   219→            std::size_t bytes_transferred)
   220→    {
   221→        SOFA_PBRPC_FUNCTION_TRACE;
   222→
   223→        if (error)
   224→        {
   225→            if (error != boost::asio::error::eof)
   226→            {
   227→#if defined( LOG )
   228→                LOG(ERROR) <<  "on_read_some(): " << RpcEndpointToString(_remote_endpoint)
   229→                           << ": read error: " << error.message();
   230→#else
   231→                SLOG(ERROR, "on_read_some(): %s: read error: %s",
   232→                        RpcEndpointToString(_remote_endpoint).c_str(),
   233→                        error.message().c_str());
   234→#endif
   235→            }
   236→
   237→            close(error.message());
   238→            return;
   239→        }
   240→
   241→        _last_rw_ticks = _ticks;
   242→        ++_total_received_count;
   243→        _total_received_size += bytes_transferred;
   244→
   245→        std::deque<ReceivedItem> received_messages;
   246→        if (!split_and_process_message(_receiving_data, 
   247→                    static_cast<int>(bytes_transferred), &received_messages))
   248→        {
   249→            close("broken stream");
   250→            return;
   251→        }
   252→
   253→        _receiving_data += bytes_transferred;
   254→        _receiving_size -= bytes_transferred;
   255→
   256→        // check if current tran buf is used out
   257→        if (_receiving_size == 0 && !reset_tran_buf())
   258→        {
   259→            close("out of memory");
   260→            return;
   261→        }
   262→
   263→        // release token
   264→        atomic_comp_swap(&_receive_token, TOKEN_FREE, TOKEN_LOCK);
   265→
   266→        // trigger next receive
   267→        try_start_receive();
   268→
   269→        // process messages
   270→        while (!is_closed() && !received_messages.empty())
   271→        {
   272→            const ReceivedItem& item = received_messages.front();
   273→            on_received(item.message, item.meta_size, item.data_size);
   274→            received_messages.pop_front();
   275→        }
   276→    }
   277→
   278→    // Callback of "async_write_some()".
   279→    virtual void on_write_some(
   280→            const boost::system::error_code& error,
   281→            std::size_t bytes_transferred)
   282→    {
   283→        SOFA_PBRPC_FUNCTION_TRACE;
   284→
   285→        if (error)
   286→        {
   287→#if defined( LOG )
   288→            LOG(ERROR) << "on_write_some(): " << RpcEndpointToString(_remote_endpoint)
   289→                       << ": write error: " << error.message();
   290→#else
   291→            SLOG(ERROR, "on_write_some(): %s: write error: %s",
   292→                    RpcEndpointToString(_remote_endpoint).c_str(),
   293→                    error.message().c_str());
   294→#endif
   295→
   296→            on_send_failed(RPC_ERROR_CHANNEL_BROKEN, _sending_message, _sending_cookie);
   297→            clear_sending_env();
   298→
   299→            close(error.message());
   300→            return;
   301→        }
   302→
   303→        _last_rw_ticks = _ticks;
   304→        _sent_size += bytes_transferred;
   305→        ++_total_sent_count;
   306→        _total_sent_size += bytes_transferred;
   307→
   308→        if (static_cast<int>(bytes_transferred) == _sending_size)
   309→        {
   310→            // seek to the next buf handle
   311→            if (_sending_message->Next(
   312→                        reinterpret_cast<const void**>(&_sending_data),
   313→                        &_sending_size))
   314→            {
   315→                // more buf to send
   316→                async_write_some(_sending_data, _sending_size);
   317→            }
   318→            else
   319→            {
   320→                // current message is completely sent
   321→                SCHECK_EQ(_sent_size, _sending_message->ByteCount());
   322→
   323→                // call hook function
   324→                on_sent(_sending_message, _sending_cookie);
   325→                clear_sending_env();
   326→
   327→                // release token
   328→                atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   329→
   330→                // trigger next send
   331→                try_start_send();
   332→
   333→                // trigger next receive if it is server, because receiving operator
   334→                // in server may be hanged for pending buffer full.
   335→                if (_role_type == ROLE_TYPE_SERVER)
   336→                    try_start_receive();
   337→            }
   338→        }
   339→        else
   340→        {
   341→            // only sent part of the data
   342→            SCHECK_LT(static_cast<int>(bytes_transferred), _sending_size);
   343→            
   344→            // start sending the remaining data
   345→            _sending_data += bytes_transferred;
   346→            _sending_size -= bytes_transferred;
   347→            async_write_some(_sending_data, _sending_size);
   348→        }
   349→    }
   350→
   351→    // Put an item into back of the pending queue.
   352→    //
   353→    // @return false if the pending queue is full.
   354→    void put_into_pending_queue(
   355→            const ReadBufferPtr& message,
   356→            const SendCookie& cookie)
   357→    {
   358→        SOFA_PBRPC_FUNCTION_TRACE;
   359→
   360→        ScopedLocker<FastLock> _(_pending_lock);
   361→        _pending_calls.push_back(PendingItem(message, cookie));
   362→        ++_pending_message_count;
   363→        _pending_data_size += message->TotalCount();
   364→        _pending_buffer_size += message->BlockCount() * TranBufPool::block_size();
   365→    }
   366→
   367→    // Insert an item into front of the pending queue.
   368→    //
   369→    // @return false if the pending queue is full.
   370→    void insert_into_pending_queue(
   371→            const ReadBufferPtr& message,
   372→            const SendCookie& cookie)
   373→    {
   374→        SOFA_PBRPC_FUNCTION_TRACE;
   375→
   376→        _swapped_calls.push_front(PendingItem(message, cookie));
   377→        ++_swapped_message_count;
   378→        _swapped_data_size += message->TotalCount();
   379→        _swapped_buffer_size += message->BlockCount() * TranBufPool::block_size();
   380→    }
   381→
   382→    // Get an item from the pending queue.
   383→    //
   384→    // @return false if the pending queue is empty.
   385→    bool get_from_pending_queue(
   386→            ReadBufferPtr* message,
   387→            SendCookie* cookie)
   388→    {
   389→        SOFA_PBRPC_FUNCTION_TRACE;
   390→
   391→        if (_swapped_calls.empty() && _pending_message_count > 0)
   392→        {
   393→            // swap from _pending_calls
   394→            ScopedLocker<FastLock> _(_pending_lock);
   395→            if (!_pending_calls.empty())
   396→            {
   397→                _swapped_calls.swap(_pending_calls);
   398→                _swapped_message_count = _pending_message_count;
   399→                _swapped_data_size = _pending_data_size;
   400→                _swapped_buffer_size = _pending_buffer_size;
   401→                _pending_message_count = 0;
   402→                _pending_data_size = 0;
   403→                _pending_buffer_size = 0;
   404→            }
   405→        }
   406→
   407→        if (!_swapped_calls.empty())
   408→        {
   409→            // fetch the top one
   410→            *message = _swapped_calls.front().message;
   411→            *cookie = _swapped_calls.front().cookie;
   412→            _swapped_calls.pop_front();
   413→            // update stats
   414→            --_swapped_message_count;
   415→            _swapped_data_size -= (*message)->TotalCount();
   416→            _swapped_buffer_size -= (*message)->BlockCount() * TranBufPool::block_size();
   417→            return true;
   418→        }
   419→
   420→        // no message found
   421→        SCHECK_EQ(0, _swapped_message_count);
   422→        SCHECK_EQ(0, _swapped_data_size);
   423→        SCHECK_EQ(0, _swapped_buffer_size);
   424→        return false;
   425→    }
   426→
   427→    // Try to start receiving messages.  It will check that receiving is allowed,
   428→    // and try to acquire the reveive token.
   429→    //
   430→    // If failed, the receiving is ignored.
   431→    // If succeed, the token must be acquired.
   432→    bool try_start_receive()
   433→    {
   434→        SOFA_PBRPC_FUNCTION_TRACE;
   435→
   436→        if (_receive_token == TOKEN_LOCK)
   437→        {
   438→            // no token
   439→            return false;
   440→        }
   441→
   442→        if (_read_quota_token <= 0)
   443→        {
   444→            // last acquire quota failed
   445→            return false;
   446→        }
   447→
   448→        if (_role_type == ROLE_TYPE_SERVER
   449→                && _pending_buffer_size > _max_pending_buffer_size)
   450→        {
   451→            // sending buffer full, should suspend receiving to wait
   452→            return false;
   453→        }
   454→
   455→        bool started = false;
   456→        if (is_connected() 
   457→                && atomic_comp_swap(&_receive_token, TOKEN_LOCK, TOKEN_FREE) == TOKEN_FREE)
   458→        {
   459→            SCHECK(_receiving_data != NULL);
   460→            SCHECK(_receiving_size > 0);
   461→            if((_read_quota_token = _flow_controller->acquire_read_quota(_receiving_size)) <= 0)
   462→            {
   463→                // no network quota
   464→                atomic_comp_swap(&_receive_token, TOKEN_FREE, TOKEN_LOCK);
   465→            }
   466→            else
   467→            {
   468→                // now start receive
   469→                async_read_some(_receiving_data, _receiving_size);
   470→                started = true;
   471→            }
   472→        }
   473→        return started;
   474→    }
   475→
   476→    // Try to start sending a message.  It will check that sending is allowed,
   477→    // and try to acquire the send token.
   478→    //
   479→    // If failed, the sending is ignored.
   480→    // If succeed, the token must be acquired.
   481→    bool try_start_send()
   482→    {
   483→        SOFA_PBRPC_FUNCTION_TRACE;
   484→
   485→        if (_send_token == TOKEN_LOCK)
   486→        {
   487→            // no token
   488→            return false;
   489→        }
   490→
   491→        if (_write_quota_token <= 0)
   492→        {
   493→            // last acquire quota failed
   494→            return false;
   495→        }
   496→
   497→        bool started = false;
   498→        while (is_connected() 
   499→                && atomic_comp_swap(&_send_token, TOKEN_LOCK, TOKEN_FREE) == TOKEN_FREE)
   500→        {
   501→            if (get_from_pending_queue(&_sending_message, &_sending_cookie))
   502→            {
   503→                if (!on_sending(_sending_message, _sending_cookie))
   504→                {
   505→                    // need not send
   506→                    on_send_failed(RPC_ERROR_REQUEST_CANCELED, _sending_message, _sending_cookie);
   507→                    clear_sending_env();
   508→
   509→                    atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   510→                }
   511→                else if ((_write_quota_token =_flow_controller->acquire_write_quota(
   512→                                _sending_message->TotalCount())) <= 0)
   513→                {
   514→                    // no network quota
   515→                    insert_into_pending_queue(_sending_message, _sending_cookie);
   516→                    clear_sending_env();
   517→
   518→                    atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   519→                    break;
   520→                }
   521→                else
   522→                {
   523→                    // now send
   524→                    _sent_size = 0;
   525→                    bool ret = _sending_message->Next(
   526→                            reinterpret_cast<const void**>(&_sending_data), &_sending_size);
   527→                    SCHECK(ret);
   528→                    async_write_some(_sending_data, _sending_size);
   529→                    started = true;
   530→                    break;
   531→                }
   532→            }
   533→            else
   534→            {
   535→                // empty pending queue
   536→                atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   537→                break;
   538→            }
   539→        }
   540→        return started;
   541→    }
   542→
   543→    // Process "data", split message, and store found messages.
   544→    //
   545→    // @return true if no error occured, and found messages are stored
   546→    //              in "received_messages", may be empty.
   547→    // @return false if error occured, for example bad message stream.
   548→    struct ReceivedItem;
   549→    bool split_and_process_message(char* data, int size,
   550→            std::deque<ReceivedItem>* received_messages)
   551→    {
   552→        SOFA_PBRPC_FUNCTION_TRACE;
   553→
   554→        while (size > 0)
   555→        {
   556→            if (!_receiving_header_identified)
   557→            {
   558→                int consumed;
   559→                int identify_result = identify_message_header(data, size, &consumed);
   560→                if (identify_result > 0)
   561→                {
   562→                    _receiving_header_identified = true;
   563→                    if (consumed == size && _receiving_header.message_size > 0)
   564→                    {
   565→                        // all the data is consumed by header, and message data is not null
   566→                        return true;
   567→                    }
   568→                    else
   569→                    {
   570→                        data += consumed;
   571→                        size -= consumed;
   572→                    }
   573→                }
   574→                else if (identify_result == 0)
   575→                {
   576→                    // in-complete header
   577→                    return true;
   578→                }
   579→                else // identify_result < 0
   580→                {
   581→                    return false;
   582→                }
   583→            }
   584→
   585→            int64 message_size = _receiving_header.message_size;
   586→            if (_received_message_size + size < message_size)
   587→            {
   588→                // all the remaining data belongs to the in-complete message
   589→                _receiving_message->Append(BufHandle(_tran_buf, size, data - _tran_buf));
   590→                _received_message_size += size;
   591→                return true;
   592→            }
   593→
   594→            int64 consume_size = message_size - _received_message_size;
   595→            if (consume_size > 0)
   596→            {
   597→                _receiving_message->Append(BufHandle(_tran_buf, consume_size, data - _tran_buf));
   598→            }
   599→            received_messages->push_back(ReceivedItem(_receiving_message, 
   600→                        _receiving_header.meta_size, _receiving_header.data_size));
   601→            reset_receiving_env();
   602→            data += consume_size;
   603→            size -= consume_size;
   604→        }
   605→
   606→        return true;
   607→    }
   608→
   609→    // Identify a message header.
   610→    //
   611→    // @return 1  a header identified.  The header is stored in "_receiving_header",
   612→    // @return 0  no header identified for incomplete data reason.  All the data is
   613→    //            consumed and copied into "_receiving_header".
   614→    // @return -1  the message stream is broken.
   615→    int identify_message_header(char* data, int size, int* consumed)
   616→    {
   617→        // copy the data into the correct position of the header
   618→        int header_size = static_cast<int>(sizeof(_receiving_header));
   619→        int copy_size = std::min(size, header_size - _received_header_size);
   620→        memcpy(reinterpret_cast<char*>(&_receiving_header) + _received_header_size,
   621→                data, copy_size);
   622→        _received_header_size += copy_size;
   623→        *consumed = copy_size;
   624→
   625→        if (_received_header_size < header_size)
   626→        {
   627→            // in-complete header
   628→            return 0;
   629→        }
   630→        else // complete header
   631→        {
   632→            // check header magic str
   633→            if (!_receiving_header.CheckMagicString())
   634→            {
   635→#if defined( LOG )
   636→                LOG(ERROR) << "identify_message_header(): " << RpcEndpointToString(_remote_endpoint)
   637→                           << ": check magic string failed: " << _receiving_header.magic_str_value;
   638→#else
   639→                SLOG(ERROR, "identify_message_header(): %s: check magic string failed: 0x%8x",
   640→                        RpcEndpointToString(_remote_endpoint).c_str(), _receiving_header.magic_str_value);
   641→#endif
   642→                return -1;
   643→            }
   644→            if (_receiving_header.meta_size + _receiving_header.data_size != _receiving_header.message_size)
   645→            {
   646→#if defined( LOG )
   647→                LOG(ERROR) << "identify_message_header(): " << RpcEndpointToString(_remote_endpoint)
   648→                           << ": check size in header failed"
   649→                           << ": meta_size=" << _receiving_header.meta_size
   650→                           << ", data_size=" << _receiving_header.data_size
   651→                           << ", message_size=" << _receiving_header.message_size;
   652→#else
   653→                SLOG(ERROR, "identify_message_header(): %s: "
   654→                        "check size in header failed: meta_size=%d, data_size=%lld, message_size=%lld",
   655→                        RpcEndpointToString(_remote_endpoint).c_str(),
   656→                        _receiving_header.meta_size,
   657→                        _receiving_header.data_size,
   658→                        _receiving_header.message_size);
   659→#endif
   660→                return -1;
   661→            }
   662→            return 1;
   663→        }
   664→    }
   665→
   666→    // Clear temp variables for sending message.
   667→    void clear_sending_env()
   668→    {
   669→        _sending_message.reset();
   670→        _sending_cookie = SendCookie();
   671→        _sent_size = 0;
   672→        _sending_data = NULL;
   673→        _sending_size = 0;
   674→    }
   675→
   676→    // Reset temp variables for receiving message.
   677→    void reset_receiving_env()
   678→    {
   679→        _receiving_message.reset(new ReadBuffer());
   680→        _received_message_size = 0;
   681→        _received_header_size = 0;
   682→        _receiving_header_identified = false;
   683→    }
   684→
   685→    // Reset tran buf variables for receiving message.
   686→    bool reset_tran_buf()
   687→    {
   688→        if (_tran_buf != NULL)
   689→        {
   690→            // free old buf, in fact just decrease ref count
   691→            TranBufPool::free(_tran_buf);
   692→            _tran_buf = NULL;
   693→        }
   694→
   695→        _tran_buf = reinterpret_cast<char*>(TranBufPool::malloc());
   696→        if(_tran_buf == NULL)
   697→        {
   698→#if defined( LOG )
   699→            LOG(ERROR) << "reset_tran_buf(): " << RpcEndpointToString(_remote_endpoint)
   700→                       << ": malloc buffer failed: out of memory";
   701→#else
   702→            SLOG(ERROR, "reset_tran_buf(): %s: malloc buffer failed: out of memory",
   703→                    RpcEndpointToString(_remote_endpoint).c_str());
   704→#endif
   705→            return false;
   706→        }
   707→        _receiving_data = reinterpret_cast<char*>(_tran_buf);
   708→        _receiving_size = TranBufPool::block_size();
   709→        return true;
   710→    }
   711→
   712→protected:
   713→    RoleType _role_type;
   714→
   715→private:
   716→    struct PendingItem
   717→    {
   718→        ReadBufferPtr message;
   719→        SendCookie cookie;
   720→        PendingItem(const ReadBufferPtr& _message,
   721→                    const SendCookie& _cookie)
   722→            : message(_message)
   723→            , cookie(_cookie) {}
   724→    };
   725→
   726→    struct ReceivedItem
   727→    {
   728→        ReadBufferPtr message;
   729→        int meta_size;
   730→        int64 data_size;
   731→        ReceivedItem(const ReadBufferPtr& _message,
   732→                     int _meta_size,
   733→                     int64 _data_size)
   734→            : message(_message)
   735→            , meta_size(_meta_size)
   736→            , data_size(_data_size) {}
   737→    };
   738→
   739→    // TODO improve sync queue performance
   740→    volatile int _pending_message_count;
   741→    volatile int64 _pending_data_size;
   742→    volatile int64 _pending_buffer_size;
   743→    std::deque<PendingItem> _pending_calls;
   744→    FastLock _pending_lock;
   745→    std::deque<PendingItem> _swapped_calls;
   746→    volatile int _swapped_message_count;
   747→    volatile int64 _swapped_data_size;
   748→    volatile int64 _swapped_buffer_size;
   749→
   750→    // flow control
   751→    FlowControllerPtr _flow_controller;
   752→    int64 _max_pending_buffer_size;
   753→    volatile int32 _read_quota_token;  // <=0 means no quota
   754→    volatile int32 _write_quota_token; // <=0 means no quota
   755→
   756→    // statistics
   757→    int64 _total_sent_count;
   758→    int64 _total_sent_size;
   759→    int64 _total_received_count;
   760→    int64 _total_received_size;
   761→
   762→    // temp variables for sending message
   763→    ReadBufferPtr _sending_message; //current sending message
   764→    SendCookie _sending_cookie; // cookie of the message
   765→    int64 _sent_size; // current sent size of the message
   766→    const char* _sending_data; // current sending data, weak ptr
   767→    int _sending_size; // size of the current sending data
   768→
   769→    // temp variables for receiving message
   770→    ReadBufferPtr _receiving_message; // current receiving message
   771→    int64 _received_message_size; // current received size of the message
   772→    RpcMessageHeader _receiving_header;
   773→    int _received_header_size;
   774→    bool _receiving_header_identified;
   775→
   776→    // tran buf for reading data
   777→    char* _tran_buf; // strong ptr
   778→    char* _receiving_data; // weak ptr
   779→    int64 _receiving_size;
   780→
   781→    // send and receive token
   782→    static const int TOKEN_FREE = 0;
   783→    static const int TOKEN_LOCK = 1;
   784→    volatile int _send_token;
   785→    volatile int _receive_token;
   786→}; // class RpcMessageStream
   787→
   788→} // namespace pbrpc
   789→} // namespace sofa
   790→
   791→#endif // _SOFA_PBRPC_RPC_MESSAGE_STREAM_H_
   792→
   793→/* vim: set ts=4 sw=4 sts=4 tw=100 */
   794→

